var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헉… 헉…","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니.","JPN":"お母さん。","ENG":"Mother?","TWN":"媽媽？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저 하늘엔 별들이 왜 저렇게 많아요?","JPN":"空にはなんであんなに星がたくさんあるんですか？","ENG":"Why are there so many stars up in the sky?","TWN":"天上面，為什麼會有那麼多的星星？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"사람들의 소망이 저 하늘에 모이기 때문이란다.","JPN":"皆の願いがあの空に集まるからだよ。","ENG":"That's because people's wishes gather in the sky.","TWN":"因為呀，大家的願望都聚集在那片天空之中了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그 소망은 하늘에 박힌 별이 되어서 저렇게 반짝이는 거지.","JPN":"そしてその願いは空を飾る星になって、ああやって輝くの。","ENG":"And those wishes become twinkling stars.","TWN":"然後，那些願望就會變成嵌在天空當中的星星，一閃一閃地發著光芒。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저 중에 제 별도 있을까요?","JPN":"あの中に、私の星もあるかな？","ENG":"Do you think my star is up there too?","TWN":"哇！在那中間會有我的星星嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼. 당연하지.","JPN":"もちろん。","ENG":"Yes, of course.","TWN":"當然了～"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 소망이 너무 커지면 말이야, 그 소망을 담고 있던 별이 톡 하고 빠져서 땅으로 떨어진단다.","JPN":"あとね、願いが大きくなると、願いを宿していた星がぽつりと地面に落ちてくるのよ。","ENG":"When a wish becomes too big, the star gets too heavy and falls down to the ground.","TWN":"而且如果願望變得很大很大，承載那個願望的星星就會啪地一聲掉到地上。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 떨어진 별은 그 사람을 찾아가서 소망을 실제로 이뤄준다고 해.","JPN":"そうやって落ちた星は、願いをかけた人のもとにやってきて願いを叶えてくれるんだって。","ENG":"It's said that a fallen star will go find its wish's owner and make it come true.","TWN":"那顆墜落的星星會找到許下願望的那個人，並實現他的願望。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아- 대단해.","JPN":"わあ～すごい。","ENG":"Wow! That's incredible.","TWN":"哇——真厲害！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니도 소원을 빌었어요? 별님이 떨어졌나요?","JPN":"お母さんもお願いしたんですか？　お星さまは落ちました？","ENG":"Did you make a wish too, Mother? Did yours fall down to earth?","TWN":"媽媽也許願了嗎？有星星掉下來了嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"그러엄-","JPN":"そうだよ～","ENG":"Of course, it did.","TWN":"那樣啊——"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"내 별은 이미 오래 전에 떨어져서 소원을 이뤄줬거든.","JPN":"私の星はとっくに落ちて、願いを叶えてくれたの。","ENG":"My star fell a long time ago and made my wish come true.","TWN":"我的星星在很久之前就已經墜落下來，實現了我的願望。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그럼 그 소원이 무엇이었냐는 내 질문에…","JPN":"何を願ったのか尋ねると……","ENG":"And when I asked what that wish was...","TWN":"那時候，我問媽媽那個願望是什麼……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"어머니는 조용히 웃으며 날 안아줄 뿐이었다.","JPN":"お母さんはただ笑って、私を抱きしめてくれた。","ENG":"Mother silently smiled and hugged me.","TWN":"她只是靜靜地笑著抱住了我。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"그때는 그 행동에 담긴 의미를 이해하지 못했다.","JPN":"あの時は、その行動の意味が分からなかった。","ENG":"At the time, I didn't understand what that meant.","TWN":"那時的我還無法理解這個動作背後的意義。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그저 어머니의 품이 사랑스럽고 따스하다고만 생각했다.","JPN":"ただ、お母さんの腕の中が温かくて心地良かった。","ENG":"I just thought that it was warm and loving in Mother's embrace.","TWN":"只是覺得媽媽的懷抱既有愛又溫暖。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헉… 헉…!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff*","TWN":"哈…… 哈……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"별님의 빛이 향하는 곳으로… 무작정 쫓아간다.","JPN":"お星さまの光が指すほうへ……ただひたすら走って行く。","ENG":"I started running... toward where the star was twinkling.","TWN":"去星星指引的地方吧！向著那裡一直奔跑……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"하늘만 바라보며, 우거진 수풀 사이를 달린다.","JPN":"空を見つめながら、茂みの中を駆ける。","ENG":"With my eyes locked at the sky, I ran through the thicket.","TWN":"望著天空，在茂密的樹叢間不停追趕。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 저 빛이 있는 자리에 내가 원하는 대답이 있을지도 모른다는…","JPN":"もしかしたら、あの光の元に行けば、私の求める答えが得られるかもしれない……","ENG":"I thought to myself...","TWN":"我輕輕地對自己說著……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"그런 막연한 생각을 하면서.","JPN":"漠然とした期待を抱いて。","ENG":"that the answer I was looking for could be where that light had fallen.","TWN":"也許在那裡，會有我想要的答案……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"하아… 하…","JPN":"はあ……はぁ……","ENG":"*Huff* *Huff*","TWN":"哈啊……哈……"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여긴…?","JPN":"ここは……？","ENG":"This place is...","TWN":"這裡是……？"},"stage":{"bg":"SWORDGRAVE_STAR","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};